/// <summary>
/// The controller of Purchase order fixation ER report
/// </summary>
class ETG_PurchOrderFixationERController extends ERFormatMappingRunBaseController
{
}

Method.Source:
/// <summary>
/// The main entrance of the controller
/// </summary>
/// <param name = "_args">The arguments</param>
public static void main(Args _args)
{
    PurchPurchaseOrderContract  contract;
    PurchTable                  purchTable;

    if (_args.dataset() == tableNum(PurchTable))
    {
        purchTable = _args.record();
        contract = new PurchPurchaseOrderContract();
        contract.parmRecordId(purchTable.RecId);
    }

    if (contract.parmRecordId())
    {
        ETG_PurchOrderFixationERService::generateReportByGER(contract);
    }
}

/// <summary>
/// Gets caption of the dialog.
/// </summary>
/// <returns>Caption of the dialog</returns>
public ClassDescription defaultCaption()
{
    return "Purchase Fixation";
}
